// ここでは動物のクラス（Animal）を作ります。
public class Animal {
  // 「鳴く」メソッドを作ります。
  public void bark() {
    System.out.println("動物が鳴きます...");
  }
}

// 次に、犬のクラス（Dog）を作ります。
// ここで「extends Animal」は、Animalクラスを継承するという意味です。
public class Dog extends Animal {
  // 犬クラスにも「鳴く」メソッドが利用できます。
}

// メインメソッドで動物と犬が鳴く機能を試します。
public class Main {
  public static void main(String[] args) {
    Animal animal = new Animal();
    animal.bark(); // 動物が鳴きます...

    Dog dog = new Dog();
    dog.bark(); // 動物が鳴きます... と出力され、犬も鳴くことが確認できます。
  }
}

// 動物クラス（Animal）を定義します。
public abstract class Animal {
  public abstract void sound();
}

// 犬クラス（Dog）を定義します。Animalクラスを継承します。
public class Dog extends Animal {
  @Override
  public void sound() {
    System.out.println("ワンワン");
  }
}

// 猫クラス（Cat）を定義します。Animalクラスを継承します。
public class Cat extends Animal {
  @Override
  public void sound() {
    System.out.println("ニャー");
  }
}

// メインクラスでポリモーフィズムを実現します。
public class Main {
  public static void main(String[] args) {
    Animal myDog = new Dog();
    Animal myCat = new Cat();
    myDog.sound(); // ワンワン
    myCat.sound(); // ニャー
  }
}

// 動物クラス（Animal）を定義します。これが抽象クラスです。
public abstract class Animal {
  public abstract void sound(); // 鳴き声を出すという抽象メソッドを定義します。
}

// 犬クラス（Dog）を定義します。Animalクラスを継承します。
public class Dog extends Animal {
  @Override
  public void sound() {
    System.out.println("ワンワン"); // 犬の鳴き声を具体化します。
  }
}

// 猫クラス（Cat）を定義します。Animalクラスを継承します。
public class Cat extends Animal {
  @Override
  public void sound() {
    System.out.println("ニャー"); // 猫の鳴き声を具体化します。
  }
}

// メインクラスで動物の鳴き声を出力します。
public class Main {
  public static void main(String[] args) {
    Animal myDog = new Dog();
    Animal myCat = new Cat();
    myDog.sound(); // ワンワン
    myCat.sound(); // ニャー
  }
}

// ロボットの機能を定義するインターフェース
public interface RobotInterface {
  void walk();
  void run();
  void jump();
}

// ロボットクラス
public class MyRobot implements RobotInterface {
  @Override
  public void walk() {
    System.out.println("ロボットが歩きます。");
  }

  @Override
  public void run() {
    System.out.println("ロボットが走ります。");
  }

  @Override
  public void jump() {
    System.out.println("ロボットがジャンプします。");
  }
}

// メインクラス
public class Main {
  public static void main(String[] args) {
    RobotInterface myRobot = new MyRobot();
    myRobot.walk();
    myRobot.run();
    myRobot.jump();
  }
}

// 秘密の箱（カプセル化されたクラス）
public class SecretBox {
  private int secretNumber;

  // 秘密の数を設定するメソッド
  public void setSecretNumber(int number) {
    if (number >= 0) {
      this.secretNumber = number;
    } else {
      System.out.println("秘密の数は0以上でなければなりません。");
    }
  }

  // 秘密の数を取得するメソッド
  public int getSecretNumber() {
    return this.secretNumber;
  }
}

// メインクラス
public class Main {
  public static void main(String[] args) {
    SecretBox myBox = new SecretBox();
    myBox.setSecretNumber(5);
    System.out.println("秘密の数は" + myBox.getSecretNumber() + "です。");
  }
}

// 親クラス
public class Parent {
  public void sayHello() {
    System.out.println("Hello, I'm parent.");
  }
}

// 子クラス
public class Child extends Parent {
  @Override
  public void sayHello() {
    System.out.println("Hello, I'm child.");
  }
}

// メインクラス
public class Main {
  public static void main(String[] args) {
    Child myChild = new Child();
    myChild.sayHello(); // 子クラスでオーバーライドしたメソッドを呼び出す
  }
}
